818	/* Apply tolower() to every character of the sds string 's'. */
819	sds sdstolower(sds s) {
820	    size_t len = sdslen(s), j;
821	    for (j = 0; j < len; j++) s[j] = tolower((unsigned char)s[j]);
822	    return s;
823	}
