832	/* Reverse the sds string 's' in-place. */
833	sds sdsreverse(sds s) {
834	    size_t len = sdslen(s);
835	    if (len <= 1) return s;
836	    size_t i = 0, j = len - 1;
837	    while (i < j) {
838	        char tmp = s[i];
839	        s[i] = s[j];
840	        s[j] = tmp;
841	        i++;
842	        j--;
843	    }
844	    return s;
845	}
